// ─── Language Context ─────────────────────────────────────────────────────────
const LangCtx = createContext({ lang: "de", t: T.de });
const useLang = () => useContext(LangCtx);

// ─── Hooks ───────────────────────────────────────────────────────────────────
function useInView(threshold = 0.12) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, inView];
}

function FadeIn({ children, delay = 0 }) {
  const [ref, inView] = useInView();
  return (
    <div ref={ref} style={{
      opacity: inView ? 1 : 0,
      transform: inView ? "none" : "translateY(28px)",
      transition: `opacity 0.65s ease ${delay}s, transform 0.65s ease ${delay}s`,
    }}>{children}</div>
  );
}

// ─── Language Toggle ──────────────────────────────────────────────────────────
function LangToggle({ lang, setLang }) {
  return (
    <button
      onClick={() => setLang(l => l === "de" ? "en" : "de")}
      style={{
        fontFamily: "'DM Mono', monospace", fontSize: "0.72rem",
        padding: "0.3rem 0.85rem", borderRadius: "100px",
        border: "1px solid rgba(255,255,255,0.14)",
        background: "rgba(255,255,255,0.04)",
        color: "rgba(255,255,255,0.55)", cursor: "pointer",
        letterSpacing: "0.08em", transition: "all 0.2s",
        display: "flex", alignItems: "center", gap: "0.4rem",
      }}
      onMouseEnter={e => { e.currentTarget.style.borderColor="rgba(255,255,255,0.35)"; e.currentTarget.style.color="#fff"; }}
      onMouseLeave={e => { e.currentTarget.style.borderColor="rgba(255,255,255,0.14)"; e.currentTarget.style.color="rgba(255,255,255,0.55)"; }}
    >
      <span style={{ fontSize:"0.9rem" }}>{lang === "de" ? "🇩🇪" : "🇬🇧"}</span>
      {lang === "de" ? "EN" : "DE"}
    </button>
  );
}

// ─── Navbar ───────────────────────────────────────────────────────────────────
function Navbar({ lang, setLang }) {
  const { t } = useLang();
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  const anchors = ["about", "projects", "skills", "contact"];

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 100,
      background: scrolled ? "rgba(6,6,10,0.94)" : "transparent",
      backdropFilter: scrolled ? "blur(20px)" : "none",
      borderBottom: scrolled ? "1px solid rgba(255,255,255,0.05)" : "none",
      transition: "all 0.35s ease",
      padding: "0 clamp(1.5rem, 6vw, 5rem)",
      display: "flex", alignItems: "center", justifyContent: "space-between",
      height: "60px",
    }}>
      <span style={{ fontFamily:"'DM Mono',monospace", fontSize:"0.82rem", color:"#00FF94", letterSpacing:"0.1em" }}>
        MS<span style={{ color:"rgba(255,255,255,0.22)" }}>_dev</span>
      </span>
      <div style={{ display:"flex", alignItems:"center", gap:"clamp(1rem,3vw,2.5rem)" }}>
        {t.nav.map((link, i) => (
          <a key={link} href={`#${anchors[i]}`} style={{
            fontFamily:"'DM Mono',monospace", fontSize:"0.72rem",
            color:"rgba(255,255,255,0.38)", textDecoration:"none",
            letterSpacing:"0.06em", transition:"color 0.2s",
          }}
            onMouseEnter={e => e.target.style.color="#fff"}
            onMouseLeave={e => e.target.style.color="rgba(255,255,255,0.38)"}
          >{link}</a>
        ))}
        <LangToggle lang={lang} setLang={setLang} />
      </div>
    </nav>
  );
}

