// ─── Screenshot Carousel ──────────────────────────────────────────────────────
function ScreenshotCarousel({ screenshots, accent }) {
  const [active, setActive] = useState(0);
  return (
    <div>
      <div style={{ borderRadius:"12px", overflow:"hidden", border:`1px solid ${accent}22`,
        boxShadow:`0 20px 60px rgba(0,0,0,0.5)`, background:"#0a0a10",
        height:"260px", display:"flex", alignItems:"center", justifyContent:"center" }}>
        <img src={IMG[screenshots[active]]} alt="Screenshot"
          style={{ maxWidth:"100%", maxHeight:"100%", objectFit:"contain", transition:"opacity 0.3s" }} />
      </div>
      {screenshots.length > 1 && (
        <div style={{ display:"flex", gap:"0.5rem", justifyContent:"center", marginTop:"0.75rem" }}>
          {screenshots.map((_, i) => (
            <button key={i} onClick={() => setActive(i)} style={{
              width: i===active ? "24px" : "8px", height:"8px", borderRadius:"4px",
              border:"none", cursor:"pointer", padding:0,
              background: i===active ? accent : "rgba(255,255,255,0.12)",
              transition:"all 0.25s",
            }} />
          ))}
        </div>
      )}
    </div>
  );
}

